Script.script:
-- ===== Galdam 전술 격자 뷰 v8: +오토타일 벽선/시야음영(fog)/벽그림자(AO)/바닥질감/애니 ===== GaldamTac = GaldamTac or {} local GT = GaldamTac GT.frame = GT.frame or 0 GT.flash = GT.flash or 0 GT.smoke = GT.smoke or {}
function GT.makeWindow() if not GT.win then GT.win = Geyser.MiniConsole:new({ name = "GaldamTacWin", x = "30%", y = "13%", width = 300, height = 320, autoWrap = false, scrollBar = false, fontSize = 12, color = "black" }) GT.win:setStyleSheet([[ background-color: rgba(10,12,18,242); border: 2px solid #5a8ac8; border-radius: 8px; ]]) GT.win:hide() end end -- 격자 전체를 한눈에: 창을 w×h에 맞춰 동적 resize (뷰포트 없음, 1칸 셀) function GT.fitWindow(w, h) if not GT.win then return end local fs = (w >= 36 or h >= 36) and 10 or ((w >= 30 or h >= 30) and 11 or ((w >= 22 or h >= 22) and 13 or 16)) local cw = math.ceil(fs * 0.72) -- 글자폭 넉넉히(우측 짤림 방지) local lh = fs + 6 local px = (w * 2 + 3) * cw + 24 -- 셀 가로 2칸 + 좌우 엣지 여유 local py = (h + 7) * lh + 22 -- 헤더+출구+범례 여유(상하 짤림 방지) pcall(function() GT.win:resize(px, py) end) pcall(function() GT.win:setFontSize(fs) end) -- 화면 중앙 정렬 (좌측 쏠림 방지, 35폭 대응) pcall(function() local mw, mh = getMainWindowSize() GT.win:move(math.max(8, math.floor((mw - px) / 2)), math.max(8, math.floor(mh * 0.10))) end) end if GaldamTacSprite then if GaldamTacSprite.h1 then pcall(killAnonymousEventHandler, GaldamTacSprite.h1); GaldamTacSprite.h1 = nil end if GaldamTacSprite.h2 then pcall(killAnonymousEventHandler, GaldamTacSprite.h2); GaldamTacSprite.h2 = nil end GaldamTacSprite.onTac = function() end GaldamTacSprite.onRoom = function() end if GaldamTacSprite.win then pcall(function() GaldamTacSprite.win:hide() end); pcall(function() GaldamTacSprite.win:setStyleSheet("background-color: rgba(0,0,0,0);") end) end end
local function clampc(v) return math.max(0, math.min(255, math.floor(v))) end local function dim(rgb, m) if m >= 0.999 then return rgb end local r, g, b = rgb:match("(%d+),(%d+),(%d+)") return clampc(tonumber(r)*m)..","..clampc(tonumber(g)*m)..","..clampc(tonumber(b)*m) end local function brighten(rgb) local r, g, b = rgb:match("(%d+),(%d+),(%d+)") return clampc(tonumber(r)+84)..","..clampc(tonumber(g)+84)..","..clampc(tonumber(b)+94) end -- 가로등 따뜻한 빛무리: 셀 색을 노란빛 쪽으로 끌어올림 (g=0~1 세기) local function warmGlow(rgb, g) local r, gr, b = rgb:match("(%d+),(%d+),(%d+)") r, gr, b = tonumber(r), tonumber(gr), tonumber(b) local k = g * 0.6 r = r + (255 - r ) * k * 0.95 gr = gr + (214 - gr) * k * 0.80 b = b + (140 - b ) * k * 0.45 return clampc(r)..","..clampc(gr)..","..clampc(b) end -- 임의 색 빛무리: 셀 색을 target(tr,tg,tb)쪽으로 끌어올림 (경광등 빨강/파랑용, a=0~1 세기) local function colorGlow(rgb, a, tr, tg, tb) local r, gr, b = rgb:match("(%d+),(%d+),(%d+)") r, gr, b = tonumber(r), tonumber(gr), tonumber(b) local k = a * 0.6 return clampc(r + (tr - r) * k) .. "," .. clampc(gr + (tg - gr) * k) .. "," .. clampc(b + (tb - b) * k) end -- 좌표 해시 미세 질감: 균일 바닥색을 ±5% 흔들어 흙/아스팔트 질감 (프레임 무관=정적) local function jitter(rgb, x, y) local n = (x * 53 + y * 97 + ((x * y) % 13) * 29) % 7 local f = 0.93 + 0.02 * n local r, g, b = rgb:match("(%d+),(%d+),(%d+)") return clampc(tonumber(r)*f) .. "," .. clampc(tonumber(g)*f) .. "," .. clampc(tonumber(b)*f) end local function smAdd(g, x, y, amt, t) local k = x .. "," .. y local c = g[k] if c then c.d = math.min(10, c.d + amt) else g[k] = { d = math.min(10, amt), t = t } end end
-- 연기 셀룰러 확산: emit(소스) → diffuse(이웃) → decay. 밀폐=잔류, 야외=흩어짐+바람 function GT.smokeStep(d) local w = tonumber(d.w) or 9 local h = tonumber(d.h) or 9 local outdoor = (d.biome == "forest" or d.biome == "road" or d.biome == "sea" or d.biome == "ocean" or d.biome == "village") local g = GT.smoke or {} for _, f in ipairs(d.fx or {}) do local x, y = tonumber(f.x), tonumber(f.y) if f.t == "fire" then if y-1 >= 0 then smAdd(g, x, y-1, 3.6, "gray") end elseif f.t == "smoke" then if y-1 >= 0 then smAdd(g, x, y-1, 2.2, "gray") end elseif f.t == "teargas" then smAdd(g, x, y, 9, "gas") elseif f.t == "breath" then if y-1 >= 0 then smAdd(g, x, y-1, 1.8, "white") end elseif f.t == "steam" then if y-1 >= 0 then smAdd(g, x, y-1, 3, "white") end end end local spread = 0.5 local ng = {} for k, c in pairs(g) do local cx, cy = k:match("(%-?%d+),(%-?%d+)") cx, cy = tonumber(cx), tonumber(cy) local cd = (c.t == "gas") and 0.965 or (outdoor and 0.70 or 0.92) local dens = c.d * cd if dens > 0.35 then smAdd(ng, cx, cy, dens * (1 - spread), c.t) local nbrs if c.t == "gas" then nbrs = {{cx,cy-1,0.5},{cx,cy+1,1.2},{cx-1,cy,1.4},{cx+1,cy,1.4}} else nbrs = {{cx,cy-1,2.3},{cx,cy+1,0.5},{cx-1,cy,1},{cx+1,cy,1}} end if outdoor then nbrs[#nbrs+1] = {cx+1,cy,1.8} end local tot = 0 for _, nb in ipairs(nbrs) do tot = tot + nb[3] end local give = dens * spread for _, nb in ipairs(nbrs) do if nb[1] >= 0 and nb[1] < w and nb[2] >= 0 and nb[2] < h then smAdd(ng, nb[1], nb[2], give * nb[3] / tot, c.t) end end end end GT.smoke = ng end local function smokeActive() return next(GT.smoke or {}) ~= nil end
GT.GLYPH_MODE = "uni" -- "uni"|"ascii" — 폰트 실측 테스트(2026-06-07). 정렬 깨지면 "ascii"로 복귀 -- 타일 타입 → {u유니코드, a아스키, fg, bg}. 글리프는 데이터(타입)가 아니라 표현 — brief §2 GT.TILE = { -- terrain asphalt={u="\226\150\146",a=":",fg="86,91,97"}, dirt2={u="\226\150\145",a=".",fg="122,100,68"}, lane={u="\226\149\140",a="-",fg="207,200,159"}, crosswalk={u="=",a="=",fg="232,230,227"}, field={u="~",a="~",fg="156,107,53"}, paddy={u="\226\137\161",a="=",fg="70,160,110"}, water={u="\226\137\136",a="~",fg="74,144,217"}, clearing={u="\194\183",a=".",fg="74,68,60"}, rockground={u="^",a="^",fg="138,144,151"}, weed={u="\207\136",a="\"",fg="118,178,72"}, weed2={u="\206\189",a="'",fg="100,158,60"}, woodfloor={u=" ",a=" ",fg="120,90,56",bg="74,54,34"}, -- structure wall={u="\226\150\147",a="#",fg="166,98,78"}, building={u="\226\150\147",a="#",fg="172,150,128"}, breakwater={u="\226\150\147",a="#",fg="138,141,146"}, fence={u="\226\150\145",a=":",fg="176,150,108"}, wall_h={u="\226\148\128",a="-",fg="216,205,184"}, wall_v={u="\226\148\130",a="|",fg="216,205,184"}, corner={u="+",a="+",fg="216,205,184"}, gate={u="\226\136\143",a="+",fg="210,165,80"}, door={u="\226\150\175",a="+",fg="210,165,80"}, window={u="\226\150\161",a="o",fg="127,184,216"}, window_open={u="\226\150\171",a="-",fg="150,220,235"}, window_broken={u="\226\128\187",a="*",fg="184,206,222"}, greenhouse={u="\226\136\169",a="n",fg="200,212,216"}, tetrapod={u="X",a="X",fg="125,132,138"}, lighthouse={u="I",a="I",fg="226,75,74"}, grave={u="\206\169",a="o",fg="134,168,90"}, -- object pole={u="\206\168",a="Y",fg="160,166,172"}, tower={u="A",a="A",fg="154,160,166"}, tree={u="\226\153\163",a="&",fg="90,180,84"}, rock={u="\226\151\143",a="o",fg="155,152,162"}, tractor={u="T",a="T",fg="226,100,46"}, truck={u="u",a="u",fg="90,140,225"}, car={u="c",a="c",fg="200,205,212"}, moto={u="m",a="m",fg="154,160,166"}, boat={u="b",a="b",fg="220,227,232"}, net={u="%",a="%",fg="184,144,90"}, dryrack={u="x",a="x",fg="156,107,53"}, bench={u="\226\150\164",a="\226\150\164",fg="190,150,96"}, busstop={u="B",a="B",fg="217,164,65"}, mailbox={u="!",a="!",fg="226,75,74"}, buoy={u="\226\151\145",a="o",fg="240,140,60"}, reef={u="\226\150\178",a="^",fg="120,150,120"}, -- 멀티셀 차량(1×2): 좌/우 반쪽 carL={u="\226\150\132",a="\226\150\132",fg="80,86,98",bg="170,178,192"}, carR={u="\226\150\132",a="\226\150\132",fg="80,86,98",bg="170,178,192"}, truckL={u="\226\150\128",a="\226\150\128",fg="44,64,116",bg="80,124,210"}, truckR={u="\226\150\132",a="\226\150\132",fg="44,64,116",bg="80,124,210"}, tracL={u="\226\150\132",a="\226\150\132",fg="96,44,22",bg="224,130,54"}, tracR={u="\226\151\143",a="\226\151\143",fg="50,50,56",bg="224,130,54"}, -- 경찰차(1×2=글자4폭): 렌더서 글자단위로 [차체][빨강][파랑][차체], 가운데2글자=경광등 점멸 policeL={u="\226\150\132",a="\226\150\132",fg="40,46,58",bg="172,178,190"}, policeR={u="\226\150\132",a="\226\150\132",fg="40,46,58",bg="172,178,190"}, -- 시골 디테일 well={u="O",a="O",fg="120,150,200"}, jangdok={u="\226\151\143",a="o",fg="98,76,58"}, dog={u="d",a="d",fg="196,136,84"}, clothes={u="\226\148\128",a="-",fg="222,222,228"}, lamp={u="\194\161",a="i",fg="246,216,132"}, fridge={u="\226\150\174",a="F",fg="208,216,224"}, sink={u="\226\151\176",a="K",fg="180,190,200"}, gasrange={u="\226\138\158",a="G",fg="120,120,128"}, cupboard={u="\226\150\168",a="c",fg="150,110,68"}, table={u="\226\150\173",a="T",fg="150,110,68"}, dtable={u="\226\150\173",a="T",fg="150,110,68"}, chair={u="\226\149\164",a="h",fg="176,134,82"}, bar={u="\226\150\172",a="B",fg="158,116,72"}, toilet={u="\226\151\147",a="t",fg="210,214,220"}, bathtub={u="\226\151\150",a="b",fg="200,214,222"}, washbasin={u="\226\151\139",a="s",fg="200,210,218"}, bed={u="\226\150\177",a="B",fg="190,170,180"}, wardrobe={u="\226\150\165",a="W",fg="130,95,60"}, desk={u="\226\151\179",a="d",fg="150,110,68"}, computer={u="\226\150\163",a="p",fg="120,132,152"}, dresser={u="\226\151\167",a="v",fg="180,150,160"}, drawers={u="\226\150\166",a="r",fg="140,100,64"}, safe={u="\226\138\160",a="X",fg="92,94,100"}, sofa={u="\226\150\172",a="S",fg="120,140,170"}, tv={u="\226\150\176",a="V",fg="64,68,76"}, bookshelf={u="\226\150\167",a="L",fg="150,110,68"}, washer={u="\226\138\159",a="m",fg="190,196,204"}, stove={u="\226\150\169",a="o",fg="120,118,126"}, tilefloor={u=" ",a=" ",fg="120,124,132",bg="70,74,82"}, deck={u="\226\148\128",a="=",fg="130,98,62",bg="66,50,32"}, } local function glyphOf(t) local e = GT.TILE[t] if not e then return "?", "200,80,80" end return ((GT.GLYPH_MODE=="uni") and e.u or e.a), e.fg, e.bg end -- 타일 종류 → 한글 이름 (마우스 hover 툴팁) GT.NAME = { lamp="가로등", wall="집 벽", fence="담장", building="건물벽", wall_h="집 벽", wall_v="집 벽", corner="집 모서리", gate="대문", door="문", window="창문", window_open="열린 창문", window_broken="깨진 창문", greenhouse="비닐하우스", tree="나무", rock="바위", well="우물", jangdok="장독대", bench="평상", carL="자동차", carR="자동차", truckL="트럭", truckR="트럭", tracL="트랙터", tracR="트랙터", policeL="경찰차", policeR="경찰차", paddy="논", field="밭", dirt2="흙길", clearing="마당", buoy="부표", reef="암초", weed="잡초", weed2="잡초", woodfloor="나무바닥", fridge="냉장고", sink="싱크대", gasrange="가스레인지", cupboard="그릇장", table="식탁", dtable="식탁", chair="의자", bar="카운터", toilet="변기", bathtub="욕조", washbasin="세면대", bed="침대", wardrobe="옷장", desk="책상", computer="컴퓨터", dresser="화장대", drawers="서랍장", safe="금고", sofa="소파", tv="티비", bookshelf="책장", washer="세탁기", stove="난로", tilefloor="타일바닥", deck="데크", }
-- ===== 벽/담장 오토타일링: 이웃 연결에 따라 선문자 자동선택 (uni 모드 전용) ===== -- 벽군=이중선(═║╔..), 담장군=단선(─│┌..). 문/창문/대문은 글리프 유지하되 연결로 취급 local WALLFAM = { wall=1, building=1, breakwater=1, wall_h=1, wall_v=1, corner=1 } local FENCEFAM = { fence=1 } local SCONN = { door=1, window=1, window_open=1, window_broken=1, gate=1 } -- mask: N=1 E=2 S=4 W=8 (1~15) local BOXD = { "\226\149\145","\226\149\144","\226\149\154","\226\149\145","\226\149\145","\226\149\148","\226\149\160","\226\149\144","\226\149\157","\226\149\144","\226\149\169","\226\149\151","\226\149\163","\226\149\166","\226\149\172" } local BOXS = { "\226\148\130","\226\148\128","\226\148\148","\226\148\130","\226\148\130","\226\148\140","\226\148\156","\226\148\128","\226\148\152","\226\148\128","\226\148\180","\226\148\144","\226\148\164","\226\148\172","\226\148\188" } local PADD = "\226\149\144" -- ═ 셀 뒷칸 채움(가로 연속) local PADS = "\226\148\128" -- ─ -- returns: 글리프(or nil=원본유지), 뒷칸패딩(" " or 가로선) local function autoTile(struct, x, y) if GT.GLYPH_MODE ~= "uni" then return nil, " " end local s = struct[x .. "," .. y] if not s then return nil, " " end local t = s.t local fam = (WALLFAM[t] and WALLFAM) or (FENCEFAM[t] and FENCEFAM) or nil if not fam then -- 문/창문/대문: 글리프는 자기 것, 동쪽이 같은 줄이면 패딩으로 선 연속 if SCONN[t] then local e = struct[(x + 1) .. "," .. y] local et = e and e.t if et and (WALLFAM[et] or SCONN[et]) then return nil, PADD elseif et and FENCEFAM[et] then return nil, PADS end end return nil, " " end local function lk(nx, ny) local n = struct[nx .. "," .. ny] return (n and (fam[n.t] or SCONN[n.t])) and 1 or 0 end local eC = lk(x + 1, y) local m = lk(x, y - 1) + eC * 2 + lk(x, y + 1) * 4 + lk(x - 1, y) * 8 if m == 0 then return nil, " " end -- 고립 기둥=원본 블록 유지 local box = (fam == WALLFAM) and BOXD or BOXS local padc = (eC == 1) and ((fam == WALLFAM) and PADD or PADS) or " " return box[m], padc end -- 플레이어 시야 차단(fog of war) / 그림자 드리우는 구조물 local FOGSOLID = { wall=1, building=1, breakwater=1, wall_h=1, wall_v=1, corner=1, door=1, gate=1, lighthouse=1, greenhouse=1 } local AOSHADOW = { wall=1, building=1, breakwater=1, wall_h=1, wall_v=1, corner=1, door=1, gate=1, lighthouse=1, greenhouse=1, window=1, window_open=1, window_broken=1 }
-- facing {fx,fy} → 방향 화살표 글리프 (1칸폭) function GT.arrowOf(fx, fy) fx = tonumber(fx) or 0; fy = tonumber(fy) or 0 if fx > 0 and fy < 0 then return "\226\134\151" -- ↗ 북동 elseif fx > 0 and fy > 0 then return "\226\134\152" -- ↘ 남동 elseif fx < 0 and fy > 0 then return "\226\134\153" -- ↙ 남서 elseif fx < 0 and fy < 0 then return "\226\134\150" -- ↖ 북서 elseif fx > 0 then return "\226\150\182" -- ▶ 동 elseif fx < 0 then return "\226\151\128" -- ◀ 서 elseif fy > 0 then return "\226\150\188" -- ▼ 남 elseif fy < 0 then return "\226\150\178" -- ▲ 북 else return "v" end end
function GT.render(d) local w = tonumber(d.w) or 9 local h = tonumber(d.h) or 9 local biome = d.biome or "indoor" local tone = tonumber(d.tone) or 3 local dark = tonumber(d.dark) or 0 local litrad = tonumber(d.litrad) or 0 local weather = d.weather or "clear" local floor = d.floor or "ondol" local outdoor = (biome == "forest" or biome == "road" or biome == "sea" or biome == "ocean" or biome == "village") local watery = (biome == "sea" or biome == "ocean") local flash = (GT.flash or 0) > 0 local watch = (tonumber(d.watch) or 0) == 1 -- 경계상황(실내/알림/수배/잠입)에서만 평시 원뿔 표시 local sx = d.self and tonumber(d.self[1]) local sy = d.self and tonumber(d.self[2]) GT.fitWindow(w, h) GT.win:clear() local nm = (gmcp.Galdam and gmcp.Galdam.Room and gmcp.Galdam.Room.name) or "전술 격자"
if (not outdoor) and dark >= 1 and litrad <= 0 then GT.win:decho("<70,72,86> \226\140\150 ???\n\n") for i = 1, math.floor(h/2) do GT.win:decho("<11,11,15>" .. string.rep("\226\150\146", w) .. "\n") end GT.win:decho("\n<120,120,140> 너무 어두워 아무것도\n<120,120,140> 보이지 않는다...\n") GT.win:decho("<90,84,70> (라이터나 손전등이 필요하다)\n") return end
local cover, actors, ground, fire, items = {}, {}, {}, {}, {} local struct, terr = {}, {} for _, s in ipairs(d.struct or {}) do struct[tonumber(s.x)..","..tonumber(s.y)] = s end for _, t in ipairs(d.terrain or {}) do terr[tonumber(t.x)..","..tonumber(t.y)] = t end for _, c in ipairs(d.cover or {}) do cover[tonumber(c.x)..","..tonumber(c.y)] = c end for _, a in ipairs(d.actors or {}) do actors[tonumber(a.x)..","..tonumber(a.y)] = a end for _, it in ipairs(d.items or {}) do items[tonumber(it.x)..","..tonumber(it.y)] = it end for _, g in ipairs(d.ground or {}) do ground[tonumber(g.x)..","..tonumber(g.y)] = g end for _, f in ipairs(d.fx or {}) do if f.t == "fire" then fire[tonumber(f.x)..","..tonumber(f.y)] = true end end -- 상호작용 객체 맵: 셀 -> {{id,name,kind},...} (가구/아이템/액터, id>0만 클릭가능) local cellObj = {} local function _addObj(cx, cy, id, nm, kind) id = tonumber(id) if not (cx and cy and id and id > 0) then return end local k = cx .. "," .. cy cellObj[k] = cellObj[k] or {} table.insert(cellObj[k], { id = tostring(id), name = nm or "?", kind = kind }) end for _, a in ipairs(d.actors or {}) do _addObj(tonumber(a.x), tonumber(a.y), a.id, a.n, "actor") end for _, it in ipairs(d.items or {}) do _addObj(tonumber(it.x), tonumber(it.y), it.id, it.n, "item") end for _, c in ipairs(d.cover or {}) do _addObj(tonumber(c.x), tonumber(c.y), c.id, c.n, "furniture") end GT.cellObj = cellObj -- 인접(체비셰프≤1) 상호작용 객체 id 집합 → 우측패널 하이라이트용 GaldamTac.nearIds = {} if sx and sy then for k, objs in pairs(cellObj) do local cx, cy = k:match("(%-?%d+),(%-?%d+)") cx, cy = tonumber(cx), tonumber(cy) if cx and math.max(math.abs(cx - sx), math.abs(cy - sy)) <= 1 then for _, o in ipairs(objs) do GaldamTac.nearIds[o.id] = true end end end end if GaldamUI and GaldamUI.refreshNearHighlight then pcall(GaldamUI.refreshNearHighlight) end local ex = {} for _, e in ipairs(d.exits or {}) do ex[e.edge] = e.dir end local smoke = GT.smoke or {}
-- 플레이어 시야 음영(fog of war): 시선이 벽에 막힌 셀은 어둑하게. -- 데이터 갱신/위치 변경시에만 재계산(onTac이 fogKey 무효화), 애니 프레임은 캐시 재사용 local fog if sx and sy then local fkey = sx .. "," .. sy .. "|" .. w .. "x" .. h if GT.fogKey == fkey and GT.fog then fog = GT.fog else fog = {} for yy = 0, h - 1 do for xx = 0, w - 1 do local fdx, fdy = xx - sx, yy - sy local steps = math.max(math.abs(fdx), math.abs(fdy)) for i = 1, steps - 1 do local cx = sx + math.floor(fdx * i / steps + 0.5) local cy = sy + math.floor(fdy * i / steps + 0.5) local s = struct[cx .. "," .. cy] if s and FOGSOLID[s.t] then fog[xx .. "," .. yy] = true; break end end end end GT.fog = fog; GT.fogKey = fkey end end
local function lightMul(x, y) if outdoor or dark < 1 then return 1.0 end if litrad <= 0 or not sx then return 0.0 end local R = litrad + 1 local dist = math.max(math.abs(x - sx), math.abs(y - sy)) if dist > R then return 0.0 end return math.max(0.14, 1.0 - dist / (R + 0.7)) end local TONE = { [1]={0.70,8,6,26},[2]={0.90,14,11,5},[3]={1.00,0,0,0},[4]={0.84,28,9,0},[5]={0.66,52,14,2},[6]={0.40,2,6,32} } local function tint(rgb) if not outdoor then return rgb end local t = TONE[tone] or TONE[3] local r, g, b = rgb:match("(%d+),(%d+),(%d+)") r = clampc(tonumber(r)*t[1]+t[2]); g = clampc(tonumber(g)*t[1]+t[3]); b = clampc(tonumber(b)*t[1]+t[4]) if weather == "fog" then r=clampc(r*0.55+58); g=clampc(g*0.55+59); b=clampc(b*0.55+61) elseif weather == "storm" then r=clampc(r*0.58+6); g=clampc(g*0.62+11); b=clampc(b*0.68+22) end return r..","..g..","..b end local function floorBg(x, y) if outdoor then if biome == "road" then local v=(x*7+y*11)%4; return ({"38,38,42","44,44,49","33,33,37","41,41,46"})[v+1] elseif watery then local v=(x+y+math.floor((GT.frame or 0)/3))%4; return ({"18,52,78","22,60,92","15,46,70","26,66,100"})[v+1] elseif biome == "village" then local v=(x*7+y*11+x*y)%4; return ({"58,49,37","64,55,41","52,44,33","60,64,46"})[v+1] else local v=(x*7+y*11+x*y)%4; return ({"18,40,20","23,48,25","15,34,17","20,44,22"})[v+1] end end local v = (x*5+y*7)%3 if floor == "wood" then return ({"46,35,24","52,41,29","41,31,21"})[v+1] elseif floor == "hardwood" then return ({"78,56,34","86,62,38","70,50,30"})[v+1] elseif floor == "tile" then return ((x+y)%2==0) and "54,58,66" or "46,50,58" elseif floor == "marble" then return ((x+y)%2==0) and "80,82,88" or "70,72,79" elseif floor == "stone" then return ({"54,54,58","61,61,65","48,48,52"})[v+1] elseif floor == "concrete" then return ({"40,42,46","45,47,51","37,39,43"})[v+1] elseif floor == "carpet" then return ({"66,28,30","74,32,34","60,25,27"})[v+1] elseif floor == "carpet_blue" then return ({"30,40,64","34,45,70","26,36,58"})[v+1] elseif floor == "carpet_green" then return ({"32,54,42","36,60,46","28,48,38"})[v+1] elseif floor == "linoleum" then return ((x+y)%2==0) and "98,97,88" or "92,91,82" elseif floor == "dirt" then return ({"54,44,32","60,49,36","48,39,28"})[v+1] else return ({"104,98,62","112,106,68","96,90,56"})[v+1] end end local function cellBg(x, y) if fire[x..","..y] then return "70,26,8" end local sm = smoke[x..","..y] if sm and sm.d >= 3 then local op = math.min(0.7, sm.d/12) local base = (sm.t=="gas") and {150,150,90} or ((sm.t=="white") and {180,182,188} or {95,95,102}) local fb = floorBg(x,y); local r,g,b = (outdoor and tint(fb) or fb):match("(%d+),(%d+),(%d+)") return clampc(tonumber(r)*(1-op)+base[1]*op)..","..clampc(tonumber(g)*(1-op)+base[2]*op)..","..clampc(tonumber(b)*(1-op)+base[3]*op) end local g = ground[x..","..y] if g and g.t == "blood" then local l=tonumber(g.l) or 1; return (32+l*24)..",9,11" elseif g and g.t == "wet" then return "24,38,58" elseif g and g.t == "snow" then return "70,76,88" end return tint(jitter(floorBg(x, y), x, y)) end
local part = {} if outdoor and (weather == "rain" or weather == "snow" or weather == "storm") then local storm = (weather == "storm") local n = storm and math.floor(w*0.95) or ((weather=="rain") and math.floor(w*0.55) or math.floor(w*0.38)) for i = 1, n do local sp = (weather=="snow") and 1 or (storm and 3 or 2) local col = (i*5+3) % w if weather == "snow" then col = (col + math.floor(GT.frame/4)) % w elseif storm then col = (col + GT.frame) % w end part[col .. "," .. (((i*3)+GT.frame*sp) % h)] = weather end end
-- 가로등 빛무리: 야간 outdoor에서 lamp 주변 반경을 따뜻하게 + 아른거림(flicker) local glow = {} local glowOn = outdoor and ({[1]=0.26, [4]=0.40, [5]=0.58, [6]=0.75})[tone] if glowOn and glowOn > 0 then for _, c in ipairs(d.cover or {}) do if c.k == "lamp" then local lx, ly = tonumber(c.x), tonumber(c.y) local fl = 0.86 + 0.14 * math.sin((GT.frame or 0) * 0.45 + lx * 1.7 + ly * 0.9) local R = 2 for ddy = -R, R do for ddx = -R, R do local gx, gy = lx + ddx, ly + ddy if gx >= 0 and gx < w and gy >= 0 and gy < h then local dist = math.max(math.abs(ddx), math.abs(ddy)) local v = (1 - dist / (R + 1)) * glowOn * fl if v > 0 then local gk = gx .. "," .. gy glow[gk] = math.min(1.0, (glow[gk] or 0) + v) end end end end end end end
-- 경찰차 경광등 빛무리: 점멸 위상에 따라 빨강/파랑이 주변으로 옅게 퍼짐 (야간일수록 강함) local pbGlow = {} local beaconOn = outdoor and ({[1]=0.34, [4]=0.50, [5]=0.66, [6]=0.85})[tone] if beaconOn and beaconOn > 0 then local on = math.floor((GT.frame or 0) / 3) % 2 local pulse = 0.72 + 0.28 * math.abs(math.sin((GT.frame or 0) * 0.9)) local tr = (on == 0) and 245 or 64 local tg = (on == 0) and 58 or 104 local tb = (on == 0) and 58 or 245 for _, c in ipairs(d.cover or {}) do if c.k == "policeL" or c.k == "policeR" then local lx, ly = tonumber(c.x), tonumber(c.y) local R = 3 for ddy = -R, R do for ddx = -R, R do local gx, gy = lx + ddx, ly + ddy if gx >= 0 and gx < w and gy >= 0 and gy < h then local dist = math.abs(ddx) + math.abs(ddy) local v = (1 - dist / (R + 1.5)) * beaconOn * pulse if v > 0 then local gk = gx .. "," .. gy local e = pbGlow[gk] if not e or v > e.v then pbGlow[gk] = {v = math.min(1.0, v), r = tr, g = tg, b = tb} end end end end end end end end
-- NPC 시야 원뿔 (코만도스식): facing+시야로 cone 셀에 누적. 평시 초록, 의심↑ 주황→빨강 local cone = {} for _, a in ipairs(d.actors or {}) do if a.k == "npc" and a.f then local ox, oy = tonumber(a.x), tonumber(a.y) local fxv, fyv = tonumber(a.f[1]), tonumber(a.f[2]) local sr = tonumber(a.sr) or 5 local ct = tonumber(a.ct) or 1 local sus = tonumber(a.sus) or 0 -- 경계상황(watch)이거나 의심중인 NPC만 원뿔 표시. 평시 공개장소=숨김 if ox and fxv and (watch or sus > 0) and (fxv ~= 0 or fyv ~= 0) then for cyy = 0, h - 1 do for cxx = 0, w - 1 do local vx, vy = cxx - ox, cyy - oy local dist = math.max(math.abs(vx), math.abs(vy)) if dist >= 1 and dist <= sr then local fdot = fxv * vx + fyv * vy local fcr = fxv * vy - fyv * vx if fdot > 0 and math.abs(fcr) <= fdot * ct then local k = cxx .. "," .. cyy local inten = (1 - dist / (sr + 1.5)) * 0.55 local e = cone[k] if not e or inten > e.v then cone[k] = { v = inten, sus = sus } end end end end end end end end
local hdr = outdoor and "<150,210,150>" or "<154,208,255>" local tnames = {"새벽","아침","낮","저녁","노을","밤"} GT.win:decho(hdr .. " \226\140\150 " .. nm) if outdoor then local sub = "(" .. (tnames[tone] or "") .. ")" if weather=="rain" then sub=sub.." 비" elseif weather=="snow" then sub=sub.." 눈" elseif weather=="fog" then sub=sub.." 안개" elseif weather=="storm" then sub=sub.." 태풍!" end GT.win:decho("<120,128,148> " .. sub) elseif dark >= 1 then GT.win:decho("<150,140,90> (불빛)") end GT.win:decho("\n") if ex.N then GT.win:decho("<150,255,150> \226\150\178 " .. ex.N .. "\n") else GT.win:decho("\n") end local fcol = {"255,150,32","255,92,20","255,205,70"} local midy = math.floor(h / 2) for y = 0, h - 1 do if y == midy and ex.W then GT.win:decho("<150,255,150>\226\151\128") else GT.win:decho(" ") end for x = 0, w - 1 do local key = x .. "," .. y local lm = lightMul(x, y) if lm <= 0.02 then GT.win:decho("<8,8,11:5,5,8> ") else local bg = cellBg(x, y) -- 벽 그림자(AO): 북쪽 이웃이 키 큰 구조물이면 남쪽(화면 아래) 셀 어둑하게 → 입체감 if not struct[key] then local ns = struct[x .. "," .. (y - 1)] if ns and AOSHADOW[ns.t] then bg = dim(bg, 0.76) elseif ns and FENCEFAM[ns.t] then bg = dim(bg, 0.88) end end local g = ground[key] local p = part[key] local sm = smoke[key] local fg, glyph local pad = " " if sx == x and sy == y then fg, glyph = "120,235,255", "@" elseif actors[key] then local a = actors[key] if a.k == "npc" then local sus = tonumber(a.sus) or 0 -- 경계상황이거나 의심중인 NPC만 시선 화살표. 평시엔 평범한 글리프 if (watch or sus > 0) and a.f and GT.arrowOf then glyph = GT.arrowOf(tonumber(a.f[1]), tonumber(a.f[2])) else glyph = "v" end if sus >= 61 then fg = "255,80,60" elseif sus >= 31 then fg = "255,150,60" elseif sus >= 1 then fg = "255,205,90" else fg = "230,200,90" end elseif a.k == "player" then fg, glyph = "120,230,120", "P" else fg, glyph = "255,90,90", "W" end elseif fire[key] then fg = fcol[((GT.frame + x + y) % 3) + 1] glyph = (((GT.frame + x) % 2) == 0) and "*" or "^" elseif sm and sm.d > 0.4 then local dd = sm.d local sv = (sm.t=="gas") and "190,190,110" or ((sm.t=="white") and "215,218,226" or "140,140,148") glyph = (dd>=5) and "#" or ((dd>=3) and ":" or ((dd>=1.5) and "." or "\194\176")) fg = sv elseif p == "rain" then fg, glyph = "120,170,225", "|" elseif p == "storm" then fg, glyph = "165,195,235", "/" elseif p == "snow" then fg, glyph = "230,235,245", "*" elseif items[key] then fg = "255,216,84" glyph = (((math.floor((GT.frame or 0) / 4) + x + y) % 7) == 0) and "+" or "*" elseif struct[key] then local gg, sfg, sbg = glyphOf(struct[key].t); fg, glyph = tint(sfg), gg if sbg then bg = tint(sbg) end local at, ap = autoTile(struct, x, y) if at then glyph = at end pad = ap elseif cover[key] then local gg, cfg, cbg = glyphOf(cover[key].k); fg, glyph = tint(cfg), gg if cbg then bg = tint(cbg) elseif terr[key] then local _c1, _c2, ctb = glyphOf(terr[key].t); if ctb then bg = tint(ctb) end end elseif g and g.t == "blood" then local l = tonumber(g.l) or 1 glyph = (l>=5) and "#" or ((l>=2) and ":" or ".") fg = (115+l*20)..",26,28" elseif g and g.t == "wet" then fg, glyph = "90,150,210", "~" elseif g and g.t == "snow" then fg, glyph = "225,232,244", "\226\151\166" elseif g and g.t == "glass" then local l = tonumber(g.l) or 1 glyph = (l>=3) and "\226\128\187" or ((l>=2) and ":" or "\194\183") fg = "172,202,226" elseif g and g.t == "mess" then local l = tonumber(g.l) or 1 glyph = (l>=2) and ";" or "," fg = "150,120,82" elseif terr[key] then local gg, tfg, tbg = glyphOf(terr[key].t); fg, glyph = tint(tfg), gg; if tbg then bg = tint(tbg) end elseif outdoor then if biome == "road" then fg, glyph = tint("90,76,54"), " " elseif watery then local ph = (x + y*2 + (GT.frame or 0)) % 5 if ph < 2 then fg, glyph = tint("90,165,205"), "~" else fg, glyph = tint("60,120,165"), "~" end else -- 풀 살랑임: 다른 애니가 돌 때만 프레임이 흘러 무비용 (정지시 정적) local gp = (x*3 + y*5 + math.floor((GT.frame or 0) / 6)) % 5 if gp == 0 then fg, glyph = tint("78,130,62"), "," else fg, glyph = tint("40,82,44"), "." end end else if floor == "wood" or floor == "hardwood" then fg = "84,68,48"; glyph = "-" elseif floor == "tile" or floor == "marble" then fg = "104,108,118"; glyph = "." elseif floor == "stone" then fg = "82,82,86"; glyph = "." elseif floor == "concrete" then fg = "66,68,74"; glyph = ((x*3+y) % 5 == 0) and ":" or "." elseif floor == "carpet" or floor == "carpet_blue" or floor == "carpet_green" then fg = "150,140,135"; glyph = "\194\176" elseif floor == "linoleum" then fg = "120,118,108"; glyph = "." elseif floor == "dirt" then fg = "92,78,58"; glyph = ((x+y*2) % 4 == 0) and "," or "." else fg = "138,128,92"; glyph = "." end end local ffg, fbg = dim(fg, lm), dim(bg, lm) if flash then ffg = brighten(ffg); fbg = brighten(fbg) end local gl = glow[key] if gl and gl > 0.02 then local cc = cover[key] if not (cc and (cc.k == "policeL" or cc.k == "policeR")) then ffg = warmGlow(ffg, gl); fbg = warmGlow(fbg, gl * 0.6) end end local pb = pbGlow[key] if pb and pb.v > 0.03 then local cc2 = cover[key] if not (cc2 and (cc2.k == "policeL" or cc2.k == "policeR")) then ffg = colorGlow(ffg, pb.v, pb.r, pb.g, pb.b); fbg = colorGlow(fbg, pb.v * 0.7, pb.r, pb.g, pb.b) end end local cn = cone[key] if cn and cn.v > 0.03 and not (cover[key] and (cover[key].k == "policeL" or cover[key].k == "policeR")) then local cr, cg, cb = 70, 200, 90 if cn.sus >= 61 then cr, cg, cb = 235, 70, 60 elseif cn.sus >= 31 then cr, cg, cb = 235, 150, 60 elseif cn.sus >= 1 then cr, cg, cb = 220, 200, 70 end -- 원뿔 숨쉬는 펄스 (애니 타이머 도는 동안) local cpulse = 0.86 + 0.14 * math.sin((GT.frame or 0) * 0.45) fbg = colorGlow(fbg, cn.v * cpulse, cr, cg, cb) end -- 시야 음영 적용: 벽 너머는 어둑하게 (자기 칸은 항상 밝게) if fog and fog[key] and not (sx == x and sy == y) then ffg = dim(ffg, 0.40); fbg = dim(fbg, 0.42) end local _pk = cover[key] and cover[key].k if (_pk == "policeL" or _pk == "policeR") and not (sx == x and sy == y) then -- 경찰차: 칸당 2글자, 좌칸=[차체][빨강] 우칸=[파랑][차체] → 가운데2글자=경광등 점멸 local on = math.floor((GT.frame or 0) / 3) % 2 local body = dim("172,178,190", lm) if flash then body = brighten(body) end local red = (on == 0) and "240,46,46" or "82,26,30" local blu = (on == 1) and "54,96,240" or "26,34,82" if fog and fog[key] then body = dim(body, 0.42); red = dim(red, 0.42); blu = dim(blu, 0.42) end local c1 = (_pk == "policeL") and body or blu local c2 = (_pk == "policeL") and red or body local r1, g1, b1 = c1:match("(%d+),(%d+),(%d+)") local r2, g2, b2 = c2:match("(%d+),(%d+),(%d+)") pcall(function() GT.win:setFgColor(20, 22, 28); GT.win:setBgColor(tonumber(r1), tonumber(g1), tonumber(b1)) GT.win:echoLink(" ", "", "경찰차", true) GT.win:setFgColor(20, 22, 28); GT.win:setBgColor(tonumber(r2), tonumber(g2), tonumber(b2)) GT.win:echoLink(" ", "", "경찰차", true) end) else local _objs = cellObj[key] local thint = nil if cover[key] then thint = GT.NAME[cover[key].k] elseif struct[key] then thint = GT.NAME[struct[key].t] elseif terr[key] then thint = GT.NAME[terr[key].t] end if _objs and #_objs > 0 and not (sx == x and sy == y) then local hint, lua if #_objs == 1 then hint = _objs[1].name lua = "GaldamUI.tacClick([[" .. _objs[1].id .. "]],[[" .. _objs[1].name .. "]])" else local nms = {} for _, oo in ipairs(_objs) do nms[#nms + 1] = oo.name end hint = "여러 개 (" .. #_objs .. "): " .. table.concat(nms, ", ") lua = "GaldamUI.tacStack(" .. x .. "," .. y .. ")" end local fr, fgc, fb = ffg:match("(%d+),(%d+),(%d+)") local br, bgc, bb = fbg:match("(%d+),(%d+),(%d+)") pcall(function() GT.win:setFgColor(tonumber(fr), tonumber(fgc), tonumber(fb)) GT.win:setBgColor(tonumber(br), tonumber(bgc), tonumber(bb)) GT.win:echoLink(glyph .. pad, lua, hint, true) end) elseif thint and not (sx == x and sy == y) then local fr, fgc, fb = ffg:match("(%d+),(%d+),(%d+)") local br, bgc, bb = fbg:match("(%d+),(%d+),(%d+)") pcall(function() GT.win:setFgColor(tonumber(fr), tonumber(fgc), tonumber(fb)) GT.win:setBgColor(tonumber(br), tonumber(bgc), tonumber(bb)) GT.win:echoLink(glyph .. pad, "", thint, true) end) else GT.win:decho("<" .. ffg .. ":" .. fbg .. ">" .. glyph .. pad) end end end end if y == midy and ex.E then GT.win:decho("<150,255,150>\226\150\182") end GT.win:echo("\n") end if ex.S then GT.win:decho("<150,255,150> \226\150\188 " .. ex.S .. "\n") else GT.win:decho("\n") end GT.win:decho("<120,130,150> @\235\130\152 N/X NPC/\236\160\129 \226\153\160\235\130\152\235\172\180 \226\151\143\235\176\148\236\156\132 \226\151\134\236\149\132\236\157\180\237\133\156\n (\236\149\132\236\157\180\236\189\152 \237\129\180\235\166\173=\236\131\129\237\152\184\236\158\145\236\154\169, \235\167\136\236\154\176\236\138\164=\237\136\180\237\140\129)\n") end
local function fxActive(d) return d and d.fx and type(d.fx)=="table" and #d.fx > 0 end -- 환경 빛 애니메이션 필요 여부: 야간 가로등 빛무리 or 경찰차 경광등 점멸 local function envAnim(d) if not d then return false end -- 시야 원뿔 표시중(경계/의심 NPC)이면 펄스 애니 local watch = (tonumber(d.watch) or 0) == 1 for _, a in ipairs(d.actors or {}) do if a.k == "npc" and a.f and (watch or (tonumber(a.sus) or 0) > 0) then return true end end if not d.cover then return false end local outdoor = (d.biome=="forest" or d.biome=="road" or d.biome=="sea" or d.biome=="ocean" or d.biome=="village") local tone = tonumber(d.tone) or 3 local nightLamp = outdoor and (tone == 1 or tone >= 4) for _, c in ipairs(d.cover) do if c.k == "policeL" or c.k == "policeR" then return true end if nightLamp and c.k == "lamp" then return true end end return false end function GT.weatherTick() if not GT.lastData then GT.wtimer = nil; return end local d = GT.lastData local wx = d.weather local anim = (wx == "rain" or wx == "snow" or wx == "storm") or fxActive(d) or smokeActive() or (d.biome == "sea" or d.biome == "ocean") or envAnim(d) if not anim then GT.wtimer = nil; return end GT.frame = (GT.frame or 0) + 1 if (GT.flash or 0) > 0 then GT.flash = GT.flash - 1 end if wx == "storm" and (GT.flash or 0) <= 0 and math.random(100) <= 5 then GT.flash = 2 end if (GT.frame % 2) == 0 then GT.smokeStep(d) end if GT.win and GT.shown then GT.render(d) end GT.wtimer = tempTimer(0.12, "GaldamTac.weatherTick()") end
function GT.onTac() local d = gmcp.Galdam and gmcp.Galdam.Tac if not d then return end GT.fogKey = nil -- 새 데이터 = 구조물 변동 가능 → 시야 음영 재계산 GT.makeWindow(); GT.lastData = d -- 타일뷰 ON이면 글리프 뷰는 양보 (타일뷰 블록이 자체 렌더) if GaldamTileView and GaldamTileView.on then GT.win:hide(); GT.shown = false; return end GT.render(d); GT.win:show(); GT.shown = true local wx = d.weather local anim = (wx == "rain" or wx == "snow" or wx == "storm") or fxActive(d) or smokeActive() or (d.biome == "sea" or d.biome == "ocean") or envAnim(d) if anim and not GT.wtimer then GT.wtimer = tempTimer(0.12, "GaldamTac.weatherTick()") end end
function GT.onRoom() if GT.win then GT.win:hide() end GT.shown = false GT.smoke = {} GT.fog = nil; GT.fogKey = nil if GT.wtimer then killTimer(GT.wtimer); GT.wtimer = nil end end
if GT.h1 then killAnonymousEventHandler(GT.h1) end if GT.h2 then killAnonymousEventHandler(GT.h2) end GT.h1 = registerAnonymousEventHandler("gmcp.Galdam.Tac", "GaldamTac.onTac") GT.h2 = registerAnonymousEventHandler("gmcp.Galdam.Room", "GaldamTac.onRoom") GT.makeWindow() echo("[Galdam] 전술 격자 뷰 v8 로드됨 (+오토타일 벽선/시야음영/벽그림자/바닥질감/풀·원뿔 애니).\n")
